func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    // Create a deep copy of the grid to avoid modifying the original
    newGrid := make([][]int64, len(grid))
    for i := range grid {
        newGrid[i] = make([]int64, len(grid[i]))
        copy(newGrid[i], grid[i])
    }

    // Iterate over the rows in the submatrix and reverse them
    for i := x; i < x+k; i++ {
        // Extract the subrow from y to y+k-1
        subrow := make([]int64, k)
        for j := y; j < y+k; j++ {
            subrow[j-y] = newGrid[i][j]
        }
        // Reverse the subrow
        for j := 0; j < len(subrow)/2; j++ {
            subrow[j], subrow[len(subrow)-1-j] = subrow[len(subrow)-1-j], subrow[j]
        }
        // Put the reversed subrow back
        for j := y; j < y+k; j++ {
            newGrid[i][j] = subrow[j-y]
        }
    }

    return newGrid
}
